<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {AlertTriangle,Building2,Flame,Newspaper,Users} from 'lucide-vue-next';import KpiCard from '../components/common/KpiCard.vue';import BaseChart from '../components/charts/BaseChart.vue';import StatusBadge from '../components/common/StatusBadge.vue';import {api} from '../api/client';const data=ref<any>(null);onMounted(async()=>data.value=await api('/news/overview'));const trend=computed(()=>({tooltip:{trigger:'axis'},grid:{left:38,right:15,top:25,bottom:28},xAxis:{type:'category',data:data.value?.heat_trend.map((x:any)=>x.time)||[]},yAxis:{type:'value',splitLine:{lineStyle:{color:'#eef2f7'}}},series:[{type:'line',smooth:true,data:data.value?.heat_trend.map((x:any)=>x.value)||[],lineStyle:{color:'#8b5cf6',width:2},areaStyle:{color:'rgba(139,92,246,.1)'}}]}))
</script>
<template><div v-if="data"><div class="kpi-grid grid"><KpiCard label="今日热点板块" :value="data.kpis.hot_sectors+'个'" change="热度持续" tone="purple" :icon="Flame"/><KpiCard label="板块异动" :value="data.kpis.sector_movements+'次'" change="较昨日 +4" tone="blue" :icon="Building2"/><KpiCard label="个股新闻" :value="data.kpis.company_news+'条'" change="近24小时" tone="green" :icon="Newspaper"/><KpiCard label="风险公告" :value="data.kpis.risk_announcements+'条'" change="需复核" tone="red" :icon="AlertTriangle"/><KpiCard label="机构调研" :value="data.kpis.institutional_research+'次'" change="本周累计" tone="orange" :icon="Users"/></div><div class="split-main"><section class="grid"><article class="panel"><div class="panel-title"><h2>板块热度排行</h2></div><div class="table-wrap"><table><thead><tr><th>排名</th><th>板块</th><th>热度</th><th>涨跌幅</th><th>成交额</th><th>主要原因</th></tr></thead><tbody><tr v-for="(x,i) in data.sectors" :key="x.id"><td>{{i+1}}</td><td><b>{{x.name}}</b></td><td><div class="progress" style="width:110px"><i :style="{width:x.heat_score+'%'}"></i></div></td><td :class="x.change_pct>0?'positive':'negative'">{{x.change_pct}}%</td><td>{{x.turnover}}亿</td><td>{{x.reasons.join(' · ')}}</td></tr></tbody></table></div></article><article class="panel chart-panel"><div class="panel-title"><h2>板块热度日内走势</h2></div><div class="panel-body"><BaseChart :option="trend" :height="250"/></div></article><article class="panel"><div class="panel-title"><h2>新闻与事件聚类</h2></div><div class="table-wrap"><table><thead><tr><th>事件</th><th>来源</th><th>时间</th><th>情绪</th></tr></thead><tbody><tr v-for="x in data.news" :key="x.id"><td><b>{{x.title}}</b><br/><small class="muted">{{x.content}}</small></td><td>{{x.source}}</td><td>{{x.publish_time?.slice(0,16).replace('T',' ')}}</td><td><StatusBadge :text="x.sentiment" :tone="x.sentiment==='positive'?'success':'info'"/></td></tr></tbody></table></div></article></section><aside class="panel agent-panel"><div class="panel-title"><span class="agent-mark"><Flame :size="17"/></span><h2>热点原因分析</h2></div><section><b>综合归因</b><p>{{data.reasoning.summary}}</p></section><section><b>相关个股</b><div v-for="x in data.related_stocks" :key="x.ts_code" class="list-item"><span>{{x.name}}</span><span :class="x.pct_chg>0?'positive':'negative'">{{x.pct_chg}}%</span></div></section><section><b>持续性观察指标</b><ul><li v-for="x in data.reasoning.indicators" :key="x">{{x}}</li></ul></section><p class="disclaimer">热点分析不等于投资价值判断，仅供研究参考。</p></aside></div></div><div v-else class="empty">正在加载新闻与板块数据...</div></template>
